var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。`,ENG:`that you'll be with him, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called him to your office. He said he'd be here soon.`,TWN:`做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`MORTAR_FOX_NULL_NULL`,text:{KOREA:`저희 실적이 우수한 비결 말입니까?`,JPN:`我々が優秀な実績を挙げている秘訣ですか？`,ENG:`You want to know how we perform so well, huh?`,TWN:`您是問我們業績優秀的秘訣嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MORTAR_FOX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`MORTAR_FOX_NULL_NULL`,text:{KOREA:`장약이 첨단이라고 해 봤자 결국 장약일 뿐이죠. 지금 저희가 쓰는 것들도 2종 침식체들에게 충분히 먹히는 화력이니까요.`,JPN:`最新の装備に頼らないからだと思います。今我々が使っている火器にも第2種侵食体に通用するだけの火力があります。`,ENG:`Charges are just charges, no matter how high-tech they are. What we're using now is good enough to be used against Category 2 C.O.`,TWN:`再尖端的彈藥也只是彈藥而已。我們現在裝備的彈藥就足以對付2級侵蝕體了。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MORTAR_FOX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`MORTAR_FOX_NULL_NULL`,text:{KOREA:`오히려 그런 첨단성에 의존하게 될수록, 사람은 요령을 잃기가 쉬워집니다.`,JPN:`新しい装備を当てにするようになると、培ってきたノウハウが失われてしまいます。`,ENG:`The more you rely on technology, the less self-sufficient you are.`,TWN:`人越是依賴尖端科技，反而越容易失去戰鬥技巧。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MORTAR_FOX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`MORTAR_FOX_NULL_NULL`,text:{KOREA:`꼭 그런 게 아니더라도, 이만큼 괜찮은 무기가 없기도 하고 말이죠.`,JPN:`まあ、そんなことを差し置いても、使い慣れた武器には愛着がありますので。`,ENG:`Besides, we haven't found any better weapon than this.`,TWN:`即使不一定是那樣，但也沒有比戰鬥技巧更好的武器了。  `},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MORTAR_FOX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`MORTAR_FOX_NULL_NULL`,text:{KOREA:`엇, 저희와 종신계약을 하고 싶으시다고요?`,JPN:`何と、私たちと終身契約を結びたいというのですか？`,ENG:`Ah, you want to hire us for life.`,TWN:`哎呀，您是想和我簽訂終身契約？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MORTAR_FOX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`MORTAR_FOX_NULL_NULL`,text:{KOREA:`이거 좌표 한 번 제대로 찍으셨군요. 여부가 있겠습니까!`,JPN:`まさか社長にロックオンしていただけるとは……是非もありません！`,ENG:`You got it, sir. You've made the right decision!`,TWN:`您已經設好座標了啊，當然沒問題了！`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MORTAR_FOX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};